const out = [];
for (const item of $input.all()) {
  const j = item.json || {};
  const path = j.path || j.filePath || j.name || '';
  if (typeof path !== 'string' || !/\.pdf$/i.test(path)) continue;
  const fileName = path.split('/').pop();
  const afspraakId = fileName.replace(/\.pdf$/i, '').split('_').pop();
  if (!afspraakId) continue;

  const eTag = j.eTag || j.etag || '';
  const lastModified = j.lastModified || j.modifiedAt || '';
  const contentLength = j.contentLength || j.size || '';
  const processedKey = [path, eTag, lastModified, contentLength].join('|');

  out.push({
    json: {
      filePath: path,
      fileName,
      afspraakId,
      eTag,
      lastModified,
      contentLength,
      processedKey,
    },
  });
}
return out;

const resp = $input.first().json || {};

function pickText(value) {
  if (value === null || value === undefined) return '';
  if (typeof value === 'string') return value;
  if (Array.isArray(value)) {
    for (const item of value) {
      const found = pickText(item);
      if (found) return found;
    }
    return '';
  }
  if (typeof value === 'object') {
    if (typeof value.text === 'string') return value.text;
    if (typeof value.output_text === 'string') return value.output_text;
    if (value.type === 'output_text' && typeof value.text === 'string') return value.text;
    for (const key of ['content', 'output', 'message', 'choices', 'data']) {
      const found = pickText(value[key]);
      if (found) return found;
    }
  }
  return '';
}

let txt =
  pickText(resp.output) ||
  pickText(resp.content) ||
  pickText(resp.text) ||
  pickText(resp);

txt = String(txt)
  .replace(/^\s*```json\s*/i, '')
  .replace(/^\s*```\s*/i, '')
  .replace(/\s*```\s*$/i, '')
  .trim();

let parsed = {};
try {
  parsed = JSON.parse(txt);
} catch (e) {
  parsed = {
    interesse: null,
    notities: '',
    verkoopgesprekStatus: null,
    vervolgactie: null,
    _parseFout: txt.slice(0, 500),
  };
}

const ref = $('Bouw ai input').item.json;

return [{
  json: {
    afspraakId: ref.afspraakId,
    fileName: ref.fileName,
    filePath: ref.filePath,
    processedKey: ref.processedKey,
    interesse: parsed.interesse ?? null,
    notities: parsed.notities ?? '',
    verkoopgesprekStatus: parsed.verkoopgesprekStatus ?? null,
    vervolgactie: parsed.vervolgactie ?? null,
    parseFout: parsed._parseFout ?? null,
    rawModelText: txt.slice(0, 1000),
  },
}];

const input = $input.first();
const bin = input.binary?.data;
if (!bin) throw new Error('Geen binaire PDF op binary.data');

const ref = $('Filter PDFs + afspraakId').item.json;

const prompt = [
  'Je leest een PNG-afbeelding van handgeschreven aantekeningen van een makelaar op een bezichtigings-cheatsheet.',
  'Geef UITSLUITEND geldige JSON terug, zonder extra tekst en zonder codeblokken.',
  'Gebruik exact deze velden:',
  '{"interesse": <geheel getal 0-100 of null>, "notities": <string of "">, "verkoopgesprekStatus": <string of null>, "vervolgactie": <string of null>}',
  'Lees alleen de handgeschreven invulling in de aantekenvakken. Laat een veld leeg ("") of null als er niets handgeschreven bij staat.'
].join('\n');

return [{
  json: {
    afspraakId: ref.afspraakId,
    fileName: ref.fileName || bin.fileName || 'cheatsheet.pdf',
    filePath: ref.filePath,
    processedKey: ref.processedKey,
    prompt,
  },
  binary: {
    data: bin,
  },
}];

const staticData = $getWorkflowStaticData('global');
staticData.processedCheatsheets ??= {};

const processed = staticData.processedCheatsheets;
const entries = Object.entries(processed);
if (entries.length > 5000) {
  entries
    .sort((a, b) => String(a[1]?.processedAt || '').localeCompare(String(b[1]?.processedAt || '')))
    .slice(0, entries.length - 5000)
    .forEach(([key]) => delete processed[key]);
}

const out = [];
for (const item of $input.all()) {
  const key = item.json.processedKey;
  if (!key) {
    out.push(item);
    continue;
  }
  if (processed[key]) continue;
  out.push(item);
}

return out;

const staticData = $getWorkflowStaticData('global');
staticData.processedCheatsheets ??= {};

const ref = $('Parse AI-output').item.json;
const key = ref.processedKey;
if (!key) throw new Error('Geen processedKey gevonden op Parse AI-output');

staticData.processedCheatsheets[key] = {
  processedAt: new Date().toISOString(),
  afspraakId: ref.afspraakId,
  fileName: ref.fileName,
  filePath: ref.filePath,
  interesse: ref.interesse ?? null,
  notities: ref.notities ?? '',
};

return [{
  json: {
    ...$input.first().json,
    processedKey: key,
    processedFile: ref.fileName,
  },
}];

const parsed = $("Parse AI-output").item.json || {};
const pdfItem = $("Download PDF").item;
const pdf = pdfItem.binary?.data;
if (!pdf) throw new Error("Geen PDF-bijlage gevonden op Download PDF");

const value = (v, fallback = "-") => {
  if (v === null || v === undefined || v === "") return fallback;
  return String(v);
};

const fileName = parsed.fileName || pdf.fileName || "bezichtiging-cheatsheet.pdf";
const interesse = value(parsed.interesse);
const notities = value(parsed.notities);
const verkoopgesprekStatus = value(parsed.verkoopgesprekStatus);
const vervolgactie = value(parsed.vervolgactie);
const afspraakId = value(parsed.afspraakId);

const subject = `Bezichtiging aantekeningen verwerkt - ${fileName}`;
const text = [
  "De bezichtigings-aantekeningen zijn verwerkt.",
  "",
  `Afspraak ID: ${afspraakId}`,
  `Bestand: ${fileName}`,
  `Interesse: ${interesse}`,
  `Notities: ${notities}`,
  `Verkoopgesprek-status: ${verkoopgesprekStatus}`,
  `Vervolgactie: ${vervolgactie}`,
  "",
  "De originele PDF staat als bijlage bij deze e-mail.",
].join("\n");

const esc = (v) =>
  value(v, "").replace(/[&<>"']/g, (c) => ({
    "&": "&amp;",
    "<": "&lt;",
    ">": "&gt;",
    '"': "&quot;",
    "'": "&#39;",
  })[c]);

const html = `
  <p>De bezichtigings-aantekeningen zijn verwerkt.</p>
  <table cellpadding="6" cellspacing="0" border="0" style="border-collapse:collapse;font-family:Arial,sans-serif;font-size:14px">
    <tr><td><strong>Afspraak ID</strong></td><td>${esc(afspraakId)}</td></tr>
    <tr><td><strong>Bestand</strong></td><td>${esc(fileName)}</td></tr>
    <tr><td><strong>Interesse</strong></td><td>${esc(interesse)}</td></tr>
    <tr><td><strong>Notities</strong></td><td>${esc(notities)}</td></tr>
    <tr><td><strong>Verkoopgesprek-status</strong></td><td>${esc(verkoopgesprekStatus)}</td></tr>
    <tr><td><strong>Vervolgactie</strong></td><td>${esc(vervolgactie)}</td></tr>
  </table>
  <p>De originele PDF staat als bijlage bij deze e-mail.</p>
`;

return [
  {
    json: {
      ...parsed,
      subject,
      text,
      html,
    },
    binary: {
      data: {
        ...pdf,
        fileName,
        mimeType: pdf.mimeType || "application/pdf",
      },
    },
  },
];
